public class WarehouseState
{
    public string WarehouseId { get; set; } = "WH-001";
    public string WarehouseName { get; set; } = "Warehouse A";

    public static readonly (string Id, string Name)[] AvailableWarehouses =
    [
        ("WH-001", "Warehouse A"),
        ("WH-002", "Warehouse B"),
        ("WH-003", "Warehouse C"),
    ];
}

namespace sv_ad0f2a9d6365460cb378382bd4893604.Services;

/// <summary>
/// Scoped service that tracks low-stock alert counts per warehouse.
/// Components subscribe to <see cref="OnChange"/> to be notified when
/// new polling data arrives — even if a different component triggered the poll.
/// Scoped lifetime ensures each user circuit gets its own instance.
/// </summary>
public class InventoryAlertService
{
    private static readonly Random s_random = new();

    public int CurrentAlertCount { get; private set; }

    public event Action? OnChange;

    /// <summary>
    /// Simulates a database query that returns the number of items below
    /// minimum stock levels for the given warehouse.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        int count = s_random.Next(0, 16);
        return Task.FromResult(count);
    }

    /// <summary>
    /// Fetches the latest count and notifies ALL subscribers.
    /// Called by whichever component owns the polling timer.
    /// </summary>
    public async Task RefreshAsync(string warehouseId)
    {
        CurrentAlertCount = await GetLowStockCountAsync(warehouseId);
        OnChange?.Invoke();
    }
}

