@rendermode InteractiveServer
@inject CascadingValueSource<WarehouseState> WarehouseSource

<select class="form-select form-select-sm" style="width:auto"
        value="@CurrentWarehouse?.WarehouseId"
        @onchange="OnWarehouseChanged">
    @foreach (var wh in WarehouseState.AvailableWarehouses)
    {
        <option value="@wh.Id">@wh.Name</option>
    }
</select>

@code {
    [CascadingParameter]
    private WarehouseState? CurrentWarehouse { get; set; }

    private async Task OnWarehouseChanged(ChangeEventArgs e)
    {
        var id = e.Value?.ToString() ?? "WH-001";
        var match = WarehouseState.AvailableWarehouses.FirstOrDefault(w => w.Id == id);
        var updated = new WarehouseState { WarehouseId = match.Id, WarehouseName = match.Name };
        await WarehouseSource.NotifyChangedAsync(updated);
    }
}

@using sv_ad0f2a9d6365460cb378382bd4893604.Services
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<span class="badge bg-danger rounded-pill ms-auto">@AlertService.CurrentAlertCount</span>

@code {
    private Action? _handler;

    protected override void OnInitialized()
    {
        // Wrap in InvokeAsync because the event may fire from a timer thread.
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
    }
}

@page "/dashboard"
@using sv_ad0f2a9d6365460cb378382bd4893604.Services
@rendermode InteractiveServer
@inject InventoryAlertService AlertService
@implements IDisposable

<PageTitle>Dashboard</PageTitle>

<h1>Warehouse Dashboard</h1>

<div class="card mt-3" style="max-width: 30rem;">
    <div class="card-body">
        <h5 class="card-title">@CurrentWarehouse?.WarehouseName</h5>
        <p class="card-text">
            Low-stock alerts:
            <span class="badge bg-danger fs-6">@AlertService.CurrentAlertCount</span>
        </p>
        <p class="text-muted mb-0">Refreshes every 10 seconds while this page is open.</p>
    </div>
</div>

@code {
    [CascadingParameter]
    private WarehouseState? CurrentWarehouse { get; set; }

    private PeriodicTimer? _timer;
    private CancellationTokenSource? _cts;
    private Action? _handler;

    protected override void OnInitialized()
    {
        _handler = () => InvokeAsync(StateHasChanged);
        AlertService.OnChange += _handler;
    }

    protected override async Task OnParametersSetAsync()
    {
        // Restart polling whenever the warehouse changes.
        await StopPollingAsync();
        if (CurrentWarehouse is not null)
        {
            await AlertService.RefreshAsync(CurrentWarehouse.WarehouseId);
            StartPolling(CurrentWarehouse.WarehouseId);
        }
    }

    private void StartPolling(string warehouseId)
    {
        _cts = new CancellationTokenSource();
        _timer = new PeriodicTimer(TimeSpan.FromSeconds(10));
        var token = _cts.Token;

        _ = Task.Run(async () =>
        {
            try
            {
                while (await _timer.WaitForNextTickAsync(token))
                {
                    await AlertService.RefreshAsync(warehouseId);
                }
            }
            catch (OperationCanceledException) { }
        });
    }

    private async Task StopPollingAsync()
    {
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
            _cts = null;
        }
        _timer?.Dispose();
        _timer = null;
    }

    public void Dispose()
    {
        AlertService.OnChange -= _handler;
        _cts?.Cancel();
        _cts?.Dispose();
        _timer?.Dispose();
    }
}

